-- GENERATED by @brain/semantic-metrics compiler — DO NOT EDIT. Change the YAML + recompile.
-- Tenancy: the BRAND_PREDICATE sentinel (below) is replaced with `brand_id = ?` by the serving seam.
CREATE OR REPLACE VIEW brain_serving.mv_metric_orders_day_slow AS
WITH base AS (
  SELECT
    brand_id,
    date_trunc('day', conversion_at) AS period,
    channel,
    COUNT(DISTINCT order_id) AS order_count
  FROM brain_serving.semantic_order
  WHERE conversion_at IS NOT NULL
    AND ${BRAND_PREDICATE}
  GROUP BY 1, 2, 3
)
SELECT
  brand_id,
  period,
  channel,
  order_count,
  (order_count) AS orders
FROM base;
